sql:
SELECT DISTINCT inmates.inmate_id, inmates.first_name
FROM inmates
INNER JOIN inmate_offenses ON inmates.inmate_id = inmate_offenses.inmate_id;

SELECT ethnicity, SUM(total_bond) AS total_bond_amount
FROM inmates
GROUP BY ethnicity;

SELECT inmate_id, book_number, last_name, middle_name, first_name, book_date, arrest_date, id_number, total_bond, bondable, inmate_info, ethnicity, weight, height, eye_color, hair_color, date_of_birth, social_security_number
FROM inmates
WHERE inmate_id = 1;

SELECT inmate_id, social_security_number
FROM inmates
WHERE inmate_id > 100;

SELECT inmate_id, last_name, middle_name, first_name 
FROM inmates 
WHERE inmate_id IN (SELECT inmate_id FROM inmate_offenses);

external_knowledge:
- "offenders carrying the weight of offenses" refers to inmates with specific offenses;
- "heavier than the typical load for their kind" means bond amounts higher than the average for their offense type;
- "average ballast in their category" refers to the average bond amount for each offense type.

sql:
SELECT COUNT(*)
FROM inmates
WHERE ethnicity = 'Caucasian';

SELECT *
FROM visitations
WHERE visit_date = '2023-05-02';

SELECT inmate_id, last_name, middle_name, first_name, (SELECT AVG(weight) FROM inmates WHERE bondable = 'No') as average_weight
FROM inmates
WHERE bondable = 'No';

SELECT last_name, first_name, total_bond 
FROM inmates 
WHERE total_bond = (SELECT MAX(total_bond) FROM inmates);

SELECT inmate_id, last_name
FROM inmates
WHERE inmate_id = (SELECT MAX(inmate_id) FROM inmates);
